"""
Gera uma folha de rota imprimível em HTML, com 2 abas:
- ETIQUETAS: uma etiqueta por pedido em grid 2 colunas (pra colar nas embalagens)
- ROTEIRO: visão compacta em linha pro motorista usar no carro

Identidade visual da Pop House: verde escuro (#008C3C) e verde claro (#64B43C).
"""
from __future__ import annotations

import html
import math
from collections import defaultdict
from datetime import date, datetime, timezone, timedelta
from pathlib import Path
from typing import Any

import pandas as pd
from loguru import logger


BRT = timezone(timedelta(hours=-3))

# Logo Pophouse embutida em base64 (PNG, 600px de largura)
LOGO_B64 = ""





# =====================================================================
# Helpers de formatação
# =====================================================================

def _safe_str(v: Any) -> str | None:
    if v is None:
        return None
    if isinstance(v, float) and math.isnan(v):
        return None
    if isinstance(v, str) and v.strip() == "":
        return None
    if isinstance(v, float) and v.is_integer():
        return str(int(v))
    return str(v).strip()


def _format_phone(phone_e164: str | None) -> str:
    if not phone_e164:
        return ""
    digits = "".join(c for c in str(phone_e164) if c.isdigit())
    if digits.startswith("55") and len(digits) >= 12:
        digits = digits[2:]
    if len(digits) == 11:
        return f"({digits[0:2]}) {digits[2:7]}-{digits[7:]}"
    if len(digits) == 10:
        return f"({digits[0:2]}) {digits[2:6]}-{digits[6:]}"
    return digits


def _format_distance_km(meters: int | float | None) -> str:
    if meters is None:
        return ""
    km = float(meters) / 1000.0
    return f"{km:.1f} km".replace(".", ",")


def _format_duration(ms: int | float | None) -> str:
    if not ms:
        return ""
    seconds = int(ms) // 1000
    hours = seconds // 3600
    minutes = (seconds % 3600) // 60
    if hours and minutes:
        return f"{hours}h{minutes:02d}min"
    if hours:
        return f"{hours}h"
    return f"{minutes}min"


def _format_time(unix_ms: int | float | None) -> str:
    if not unix_ms:
        return ""
    dt = datetime.fromtimestamp(int(unix_ms) / 1000, tz=BRT)
    return dt.strftime("%H:%M")


def _format_endereco(dest: dict[str, Any], compact: bool = False) -> str:
    if not dest:
        return ""
    partes = []
    rua = dest.get("street_address", "")
    numero = dest.get("street_number", "")
    if rua and numero:
        partes.append(f"{rua}, {numero}")
    elif rua:
        partes.append(rua)
    bairro = dest.get("neighborhood")
    if bairro and not compact:
        partes.append(bairro)
    cidade = dest.get("city")
    estado = dest.get("state")
    if cidade and estado:
        if compact:
            partes.append(cidade)
        else:
            partes.append(f"{cidade} - {estado}")
    elif cidade:
        partes.append(cidade)
    return ", ".join(partes)


# =====================================================================
# Mesclagem dos dados da Cobli com a planilha original
# =====================================================================

def _index_df_por_telefone(df: pd.DataFrame) -> dict[str, list[pd.Series]]:
    indice: dict[str, list[pd.Series]] = defaultdict(list)
    for _, row in df.iterrows():
        codigo = _safe_str(row.get("CODIGO"))
        if not codigo:
            continue
        digits = "".join(c for c in codigo if c.isdigit())
        if not digits:
            continue
        if not digits.startswith("55"):
            digits = "55" + digits
        indice[digits].append(row)
    return indice


def _enriquecer_parada(activity: dict, df_indexed: dict[str, list[pd.Series]]) -> dict[str, Any]:
    phone = activity.get("phone_number") or ""
    extras = {"volumes": None, "observacao": None, "pedido": None, "complemento": None}
    if phone and df_indexed.get(phone):
        row = df_indexed[phone].pop(0)
        extras["volumes"] = _safe_str(row.get("Volumes"))
        extras["observacao"] = _safe_str(row.get("Observação"))
        extras["pedido"] = _safe_str(row.get("Nº Pedido"))
        extras["complemento"] = _safe_str(row.get("COMPLEMENTO"))
    return extras


