# =====================================================================
# Renderização
# =====================================================================

def _render_etiqueta(numero: int, activity: dict, extras: dict) -> str:
    nome = html.escape(activity.get("name") or "Cliente")
    endereco = html.escape(_format_endereco(activity.get("destination") or {}))
    telefone = html.escape(_format_phone(activity.get("phone_number")))
    horario = _format_time(activity.get("start_time"))
    distancia = _format_distance_km(activity.get("planned_distance_in_meters"))

    linhas = []
    linhas.append(f'<div class="cliente"><span class="checkbox"></span>{nome}</div>')
    if telefone:
        linhas.append(f'<div class="linha"><span class="label">📞</span>{telefone}</div>')
    if endereco:
        linhas.append(f'<div class="linha"><span class="label">📍</span>{endereco}</div>')
    if extras.get("complemento"):
        linhas.append(
            f'<div class="linha"><span class="label">🚪</span>'
            f'<strong>Ref:</strong> {html.escape(extras["complemento"])}</div>'
        )
    if extras.get("volumes"):
        linhas.append(
            f'<div class="linha"><span class="label">📦</span>'
            f'<strong>{html.escape(extras["volumes"])} volume(s)</strong></div>'
        )
    if extras.get("pedido"):
        linhas.append(
            f'<div class="linha"><span class="label">#</span>'
            f'Pedido {html.escape(extras["pedido"])}</div>'
        )
    if extras.get("observacao"):
        linhas.append(f'<div class="obs">⚠️ {html.escape(extras["observacao"])}</div>')

    meta_top = ""
    if horario or distancia:
        partes = [p for p in [horario, distancia] if p]
        meta_top = "  " + html.escape("  •  ".join(partes))

    return f"""
    <div class="etiqueta">
      <span class="numero">#{numero}{meta_top}</span>
      {''.join(linhas)}
    </div>
    """


def _render_roteiro_linha(numero: int, activity: dict, extras: dict) -> str:
    nome        = html.escape(activity.get("name") or "Cliente")
    endereco    = html.escape(_format_endereco(activity.get("destination") or {}, compact=True))
    telefone    = html.escape(_format_phone(activity.get("phone_number")))
    horario     = _format_time(activity.get("start_time"))
    volumes     = html.escape(extras.get("volumes") or "—")
    pedido      = html.escape(extras.get("pedido") or "")
    obs         = extras.get("observacao") or ""
    complemento = extras.get("complemento") or ""

    obs_html = ""
    if obs:
        obs_html = f'<span class="obs-inline">⚠️ {html.escape(obs)}</span>'
    ref_html = ""
    if complemento:
        ref_html = f' <span style="color:#777;">(Ref: {html.escape(complemento)})</span>'

    pedido_html = f"Pedido {pedido}" if pedido else ""

    return f"""
    <tr>
      <td class="hora">{horario}</td>
      <td class="cliente-info">
        <div class="nome">{nome}</div>
        <div class="tel">📞 {telefone}</div>
        <div class="endereco">📍 {endereco}{ref_html}</div>
        {obs_html}
      </td>
      <td class="vol">📦 {volumes}</td>
      <td class="pedido">{pedido_html}</td>
    </tr>
    """


def _render_deposito(activity: dict, label: str) -> str:
    endereco = html.escape(_format_endereco(activity.get("destination") or {}))
    horario = _format_time(activity.get("start_time"))
    distancia = _format_distance_km(activity.get("planned_distance_in_meters"))
    meta = []
    if horario:
        meta.append(horario)
    if distancia and distancia != "0,0 km":
        meta.append(distancia)
    meta_str = f"  •  {'  •  '.join(meta)}" if meta else ""
    return f"""
    <div class="deposito">
      <strong>{label}</strong>{meta_str}<br>📍 {endereco}
    </div>
    """


def _render_header(rota: dict, data_rota: date) -> str:
    n_paradas       = sum(1 for a in rota.get("activities", []) if a.get("type") == "STOP")
    duracao_total   = _format_duration(rota.get("planned_duration"))
    distancia_total = _format_distance_km(rota.get("planned_distance_in_meters"))
    hora_inicio     = _format_time(rota.get("start_time"))
    hora_fim        = _format_time(rota.get("end_time"))
    data_str        = data_rota.strftime("%d/%m/%Y")
    return (
        f'<div class="rota-info">'
        f'<strong>Rota de Entrega — {data_str}</strong><br>'
        f'📦 {n_paradas} parada(s) &nbsp;·&nbsp; '
        f'📏 {distancia_total} &nbsp;·&nbsp; '
        f'⏱ {duracao_total} &nbsp;·&nbsp; '
        f'🕐 {hora_inicio} → {hora_fim}'
        f'</div>'
    )


def render_html(rota: dict, data_rota: date) -> str:
    activities = sorted(rota.get("activities", []), key=lambda a: a.get("position", 0))
    start_act = next((a for a in activities if a.get("type") == "START"), None)
    end_act = next((a for a in activities if a.get("type") == "END"), None)
    stops = [a for a in activities if a.get("type") == "STOP"]

    hora_inicio = _format_time(rota.get("start_time"))
    hora_fim = _format_time(rota.get("end_time"))

    roteiro_linhas = [
        _render_roteiro_linha(i, act, act.get("_extras_cache") or {})
        for i, act in enumerate(stops, start=1)
    ]

    header = _render_header(rota, data_rota)
    saida_html = _render_deposito(start_act, f"🚚 SAÍDA — {hora_inicio}") if start_act else ""
    retorno_html = _render_deposito(end_act, f"🏁 RETORNO — {hora_fim}") if end_act else ""

    data_str = data_rota.strftime("%d/%m/%Y")
    gerado_em = datetime.now(BRT).strftime("%d/%m/%Y %H:%M")

    return f"""<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="utf-8">
  <title>Rota Pop House — {data_str}</title>
  <style>{_CSS}</style>
</head>
<body>
  <div class="container">
    <div class="topo-bar">
      <img src="data:image/png;base64,{LOGO_B64}" alt="Pophouse"/>
      {header}
      <button class="print-btn" onclick="window.print()">🖨️ Imprimir</button>
    </div>
    <table class="roteiro-tabela">
      <thead>
        <tr>
          <th>Hora</th>
          <th>Cliente / Endereço</th>
          <th>Vol</th>
          <th>Pedido</th>
        </tr>
      </thead>
      <tbody>
        {''.join(roteiro_linhas)}
      </tbody>
    </table>
    <div class="footer">
      Gerado em {gerado_em} • Rota ID: {html.escape(rota.get('id', ''))}
    </div>
  </div>
</body>
</html>
"""


# =====================================================================
# API pública
# =====================================================================

def gerar_folha_rota(
    rotas: list[dict] | dict,
    df_original: pd.DataFrame,
    data_rota: date,
    output_dir: str | Path = "rotas",
) -> Path:
    """
    Gera a folha de rota em HTML imprimível (com 2 abas: etiquetas e roteiro).
    Retorna o Path do arquivo gerado.
    """
    if isinstance(rotas, list):
        if not rotas:
            raise ValueError("Lista de rotas vazia.")
        rota = rotas[0]
    else:
        rota = rotas

    df_indexed = _index_df_por_telefone(df_original)
    activities = sorted(rota.get("activities", []), key=lambda a: a.get("position", 0))
    for act in activities:
        if act.get("type") == "STOP":
            act["_extras_cache"] = _enriquecer_parada(act, df_indexed)

    html_content = render_html(rota, data_rota)

    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)

    filename = f"rota_{data_rota.strftime('%Y-%m-%d')}_{rota.get('id', 'sem-id')[:8]}.html"
    output_path = output_dir / filename
    output_path.write_text(html_content, encoding="utf-8")

    logger.success(f"Folha de rota gerada: {output_path.absolute()}")
    return output_path